#include <vector>
#include <algorithm>
using namespace std;

class UnionFind {
private:
    vector<int> parent;
    vector<int> rank;
public:
    UnionFind(int size) {
        parent.resize(size);
        rank.resize(size, 1);
        for (int i = 0; i < size; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    bool unionNodes(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX == rootY) return false;

        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
            rank[rootX] += rank[rootY];
        } else {
            parent[rootX] = rootY;
            rank[rootY] += rank[rootX];
        }
        return true;
    }

    int countComponents() {
        int count = 0;
        for (int i = 0; i < parent.size(); ++i) {
            if (parent[i] == i) {
                count++;
            }
        }
        return count;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    UnionFind uf(n);
    int currentComponents = n;
    if (currentComponents >= k) {
        return 0;
    }

    long long left = 0;
    long long right = edges.empty() ? 0 : edges.back()[2];
    long long answer = right;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        UnionFind tempUF(n);
        int components = n;
        for (const auto& edge : edges) {
            if (edge[2] > mid) {
                if (tempUF.find(edge[0]) != tempUF.find(edge[1])) {
                    tempUF.unionNodes(edge[0], edge[1]);
                    components--;
                }
            }
        }
        if (components >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}
